import{_ as e,o as a,c as d,a4 as i}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"硅酸盐 · 链状 / 带状","description":"","frontmatter":{"title":"硅酸盐 · 链状 / 带状","mineralGroup":"silicates-chain"},"headers":[],"relativePath":"zh/mineral-groups/silicates-chain.md","filePath":"zh/mineral-groups/silicates-chain.md","lastUpdated":1784176423000}'),r={name:"zh/mineral-groups/silicates-chain.md"};function o(n,t,l,h,s,p){return a(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="硅酸盐-·-链状-带状" tabindex="-1">硅酸盐 · 链状 / 带状 <a class="header-anchor" href="#硅酸盐-·-链状-带状" aria-label="Permalink to &quot;硅酸盐 · 链状 / 带状&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>链状硅酸盐包含两个重要宝石族：</p><ul><li><strong>辉石族（单链）</strong>：硬玉（翡翠）、透辉石、蔷薇辉石（部分属 此）、锂辉石（孔赛石）</li><li><strong>角闪石族（双链）</strong>：软玉（和田玉）、阳起石、透闪石 翡翠（硬玉）与软玉（透闪石）是中国传统&quot;玉&quot;的两大来源，但 化学与晶体结构完全不同。</li></ul><h2 id="化学式类型" tabindex="-1">化学式类型 <a class="header-anchor" href="#化学式类型" aria-label="Permalink to &quot;化学式类型&quot;">​</a></h2><p>M·SiO₃ / M₇Si₈O₂₂(OH)₂</p><h2 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h2><p>[SiO₄] 四面体通过共享两个顶角氧连接为单链（辉石）或共享两 个加一个为双链（角闪石）。链间由金属阳离子（如 Ca、Mg、Fe） 和 OH⁻ 桥接。链结构沿 c 轴延伸，使晶体常呈柱状或纤维状习性。</p><h2 id="代表性宝石" tabindex="-1">代表性宝石 <a class="header-anchor" href="#代表性宝石" aria-label="Permalink to &quot;代表性宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>化学式</th><th>亚族</th></tr></thead><tbody><tr><td>Jadeite (Burmese Jade) / 翡翠</td><td>NaAlSi₂O₆</td><td>pyroxene</td></tr><tr><td>Nephrite / 软玉</td><td>Ca₂(Mg,Fe)₅Si₈O₂₂(OH)₂</td><td>amphibole</td></tr><tr><td>Spodumene (Kunzite) / 孔赛石</td><td>LiAlSi₂O₆</td><td>pyroxene</td></tr><tr><td>Spodumene (Hiddenite) / 翠绿锂辉石</td><td>LiAlSi₂O₆ + Cr</td><td>pyroxene</td></tr><tr><td>Diopside / 透辉石</td><td>CaMgSi₂O₆</td><td>pyroxene</td></tr><tr><td>Rhodonite / 蔷薇辉石</td><td>MnSiO₃</td><td>pyroxenoid</td></tr><tr><td>Actinolite / 阳起石</td><td>Ca₂(Mg,Fe)₅Si₈O₂₂(OH)₂</td><td>amphibole</td></tr></tbody></table><p><em>详见<a href="./intro.html">矿物组总览</a>。</em></p>',11)])])}const m=e(r,[["render",o]]);export{u as __pageData,m as default};
